create table dirkspzm32.isi_resource_hist (
    sid                varchar2(2 char) not null enable,
    firma_nr           number(6, 0) not null enable,
    res_hist_id        number(*, 0) not null enable,
    in_res_id          number(*, 0) not null enable,
    in_res_start       date not null enable,
    in_res_ende        date not null enable,
    res_id             number(*, 0) not null enable,
    variante           number(*, 5) not null enable,
    artikel_id         number(*, 0),
    menge_in_container number(*, 3),
    zyk_prod_res       number(*, 5) not null enable,
    zyk_prod_ges       number(*, 5),
    linie_res_id       number(*, 0),
    login_id_verantw   number(*, 0),
    adress_id          number(*, 0)
);

alter table dirkspzm32.isi_resource_hist
    add constraint pk_resource_hist
        primary key ( sid,
                      firma_nr,
                      res_hist_id )
            using index enable;


